export const LOGO_ACCEPTED_TYPES = [
  "image/png",
  "image/jpeg",
  "image/webp",
] as const;

export const LOGO_MAX_INPUT_BYTES = 2 * 1024 * 1024;
export const LOGO_MAX_DIMENSION = 512;
export const LOGO_TARGET_MAX_BYTES = 180_000;

export type LogoPosition = "bottom-right" | "bottom-left" | "top-right";

export interface ProcessedLogo {
  dataUrl: string;
  width: number;
  height: number;
  mimeType: string;
}

function loadImage(src: string): Promise<HTMLImageElement> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = () => reject(new Error("Failed to load image"));
    img.src = src;
  });
}

function canvasToDataUrl(
  canvas: HTMLCanvasElement,
  mimeType: string,
  quality = 0.92
): string {
  if (mimeType === "image/png") {
    return canvas.toDataURL("image/png");
  }
  return canvas.toDataURL("image/jpeg", quality);
}

export async function processLogoFile(file: File): Promise<ProcessedLogo> {
  if (!LOGO_ACCEPTED_TYPES.includes(file.type as (typeof LOGO_ACCEPTED_TYPES)[number])) {
    throw new Error("Logo must be PNG, JPEG, or WebP");
  }
  if (file.size > LOGO_MAX_INPUT_BYTES) {
    throw new Error("Logo must be under 2 MB");
  }
  const objectUrl = URL.createObjectURL(file);
  try {
    const img = await loadImage(objectUrl);
    const scale = Math.min(1, LOGO_MAX_DIMENSION / Math.max(img.naturalWidth, img.naturalHeight));
    const width = Math.max(1, Math.round(img.naturalWidth * scale));
    const height = Math.max(1, Math.round(img.naturalHeight * scale));
    const canvas = document.createElement("canvas");
    canvas.width = width;
    canvas.height = height;
    const ctx = canvas.getContext("2d");
    if (!ctx) throw new Error("Could not process logo");
    ctx.drawImage(img, 0, 0, width, height);
    let mimeType = file.type === "image/webp" ? "image/png" : file.type;
    let quality = 0.92;
    let dataUrl = canvasToDataUrl(canvas, mimeType, quality);
    while (dataUrl.length > LOGO_TARGET_MAX_BYTES && quality > 0.5) {
      quality -= 0.08;
      mimeType = "image/jpeg";
      dataUrl = canvasToDataUrl(canvas, mimeType, quality);
    }
    if (dataUrl.length > LOGO_TARGET_MAX_BYTES) {
      throw new Error("Logo is too detailed — try a simpler image under 512px");
    }
    return { dataUrl, width, height, mimeType };
  } finally {
    URL.revokeObjectURL(objectUrl);
  }
}

export interface OverlayLogoOptions {
  position?: LogoPosition;
  maxWidthRatio?: number;
  paddingRatio?: number;
}

export async function overlayLogoOnImage(
  imageBase64: string,
  imageMimeType: string,
  logoDataUrl: string,
  options: OverlayLogoOptions = {}
): Promise<{ base64: string; mimeType: string }> {
  const { position = "bottom-right", maxWidthRatio = 0.18, paddingRatio = 0.04 } = options;
  const imageSrc = `data:${imageMimeType};base64,${imageBase64}`;
  const [baseImage, logoImage] = await Promise.all([loadImage(imageSrc), loadImage(logoDataUrl)]);
  const canvas = document.createElement("canvas");
  canvas.width = baseImage.naturalWidth;
  canvas.height = baseImage.naturalHeight;
  const ctx = canvas.getContext("2d");
  if (!ctx) throw new Error("Could not composite logo");
  ctx.drawImage(baseImage, 0, 0);
  const padding = Math.round(canvas.width * paddingRatio);
  const maxLogoWidth = Math.round(canvas.width * maxWidthRatio);
  const scale = Math.min(1, maxLogoWidth / logoImage.naturalWidth);
  const logoWidth = Math.round(logoImage.naturalWidth * scale);
  const logoHeight = Math.round(logoImage.naturalHeight * scale);
  let x = padding;
  let y = padding;
  if (position.includes("right")) x = canvas.width - logoWidth - padding;
  if (position.includes("bottom")) y = canvas.height - logoHeight - padding;
  ctx.drawImage(logoImage, x, y, logoWidth, logoHeight);
  const outputMime = imageMimeType === "image/jpeg" || imageMimeType === "image/webp" ? imageMimeType : "image/png";
  const dataUrl = canvasToDataUrl(canvas, outputMime, 0.92);
  const base64 = dataUrl.split(",")[1] ?? "";
  return { base64, mimeType: outputMime };
}

import { prisma } from '@/lib/db/prisma'

export interface PublishResult {
  success: boolean
  platformPostId?: string
  error?: string
  url?: string
}

export async function publishContent(itemId: string): Promise<PublishResult> {
  const item = await prisma.contentItem.findUnique({ where: { id: itemId } })
  if (!item) return { success: false, error: 'Content item not found' }
  if (!['APPROVED', 'SCHEDULED'].includes(item.status)) {
    return { success: false, error: `Item is not in a publishable state (current: ${item.status})` }
  }
  console.log(`[Publisher] Attempting to publish item ${itemId} to ${item.platform}...`)
  try {
    let result: PublishResult
    switch (item.platform) {
      case 'X': result = await publishToX(item); break
      case 'LINKEDIN': result = await publishToLinkedIn(item); break
      default: result = { success: false, error: `Publishing to ${item.platform} is not yet supported` }
    }
    if (result.success) {
      await prisma.contentItem.update({ where: { id: itemId }, data: { status: 'PUBLISHED', publishedAt: new Date() } })
      await prisma.activityLog.create({ data: { type: 'CONTENT_PUBLISHED', summary: `Published to ${item.platform}`, details: { contentItemId: itemId, platformPostId: result.platformPostId, url: result.url }, contentItemId: itemId } })
    }
    return result
  } catch (error: any) {
    return { success: false, error: error.message || 'Unknown publishing error' }
  }
}

async function publishToX(item: any): Promise<PublishResult> {
  await new Promise((res) => setTimeout(res, 800))
  return { success: true, platformPostId: 'simulated_' + Date.now(), url: `https://x.com/user/status/simulated_${Date.now()}` }
}

async function publishToLinkedIn(item: any): Promise<PublishResult> {
  await new Promise((res) => setTimeout(res, 800))
  return { success: true, platformPostId: 'li_sim_' + Date.now(), url: `https://linkedin.com/feed/update/simulated_${Date.now()}` }
}

import { prisma } from '@/lib/db/prisma'
import type { AIProvider } from '@/lib/agent/types'
import { decryptSecret, encryptSecret } from './secrets'

export const XAI_API_KEY_SETTING = 'xai_api_key'

const PROVIDER_ENV: Record<AIProvider, string> = {
  openai: 'OPENAI_API_KEY',
  anthropic: 'ANTHROPIC_API_KEY',
  xai: 'XAI_API_KEY',
  google: 'GOOGLE_AI_API_KEY',
}

function settingKeyForProvider(provider: AIProvider): string {
  return `api_key_${provider}`
}

export async function getApiKey(provider: AIProvider): Promise<string | null> {
  const envVar = PROVIDER_ENV[provider]
  if (process.env[envVar]) return process.env[envVar]!
  const keysToTry = provider === 'xai' ? [XAI_API_KEY_SETTING, settingKeyForProvider('xai')] : [settingKeyForProvider(provider)]
  try {
    for (const key of keysToTry) {
      const setting = await prisma.appSetting.findUnique({ where: { key } })
      if (setting) return decryptSecret(setting.value)
    }
    return null
  } catch { return null }
}

export async function saveApiKey(provider: AIProvider, apiKey: string): Promise<void> {
  const key = provider === 'xai' ? XAI_API_KEY_SETTING : settingKeyForProvider(provider)
  const encrypted = encryptSecret(apiKey.trim())
  await prisma.appSetting.upsert({ where: { key }, create: { key, value: encrypted }, update: { value: encrypted } })
}

export async function removeApiKey(provider: AIProvider): Promise<void> {
  const keys = provider === 'xai' ? [XAI_API_KEY_SETTING, settingKeyForProvider('xai')] : [settingKeyForProvider(provider)]
  await prisma.appSetting.deleteMany({ where: { key: { in: keys } } })
}

export async function getApiKeyStatus(provider: AIProvider) {
  const envVar = PROVIDER_ENV[provider]
  if (process.env[envVar]) {
    const key = process.env[envVar]!
    return { configured: true, source: 'env' as const, masked: `${key.slice(0, 4)}••••••••${key.slice(-4)}` }
  }
  const keysToTry = provider === 'xai' ? [XAI_API_KEY_SETTING, settingKeyForProvider('xai')] : [settingKeyForProvider(provider)]
  for (const key of keysToTry) {
    const setting = await prisma.appSetting.findUnique({ where: { key } })
    if (!setting) continue
    try {
      const decrypted = decryptSecret(setting.value)
      return { configured: true, source: 'database' as const, masked: `${decrypted.slice(0, 4)}••••••••${decrypted.slice(-4)}` }
    } catch { continue }
  }
  return { configured: false, source: null, masked: null }
}

export async function getXaiApiKey() { return getApiKey('xai') }
export async function saveXaiApiKey(apiKey: string) { return saveApiKey('xai', apiKey) }
export async function removeXaiApiKey() { return removeApiKey('xai') }
export async function getXaiApiKeyStatus() { return getApiKeyStatus('xai') }

export const ACTIVE_PROVIDER_SETTING = 'active_ai_provider'
export const MONTHLY_BUDGET_SETTING = 'monthly_budget_usd'

export async function getActiveProvider(): Promise<AIProvider> {
  try {
    const setting = await prisma.appSetting.findUnique({ where: { key: ACTIVE_PROVIDER_SETTING } })
    const value = setting?.value as AIProvider | undefined
    if (value && ['openai', 'anthropic', 'xai', 'google'].includes(value)) return value
  } catch {}
  return 'xai'
}

export async function saveActiveProvider(provider: AIProvider) {
  await prisma.appSetting.upsert({ where: { key: ACTIVE_PROVIDER_SETTING }, create: { key: ACTIVE_PROVIDER_SETTING, value: provider }, update: { value: provider } })
}

export async function getMonthlyBudget(): Promise<number | null> {
  const setting = await prisma.appSetting.findUnique({ where: { key: MONTHLY_BUDGET_SETTING } })
  if (!setting) return null
  const n = parseFloat(setting.value)
  return Number.isFinite(n) ? n : null
}

export async function saveMonthlyBudget(usd: number | null) {
  if (usd == null) { await prisma.appSetting.deleteMany({ where: { key: MONTHLY_BUDGET_SETTING } }); return }
  await prisma.appSetting.upsert({ where: { key: MONTHLY_BUDGET_SETTING }, create: { key: MONTHLY_BUDGET_SETTING, value: String(usd) }, update: { value: String(usd) } })
}

import { createCipheriv, createDecipheriv, createHash, randomBytes } from 'crypto'

const ALGORITHM = 'aes-256-gcm'
const IV_LENGTH = 12

function getEncryptionKey(): Buffer {
  const secret = process.env.SETTINGS_ENCRYPTION_KEY || process.env.DATABASE_URL || 'tekmarketing-dev-key'
  return createHash('sha256').update(secret).digest()
}

export function encryptSecret(plaintext: string): string {
  const iv = randomBytes(IV_LENGTH)
  const cipher = createCipheriv(ALGORITHM, getEncryptionKey(), iv)
  const encrypted = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()])
  const tag = cipher.getAuthTag()
  return `${iv.toString('base64')}:${tag.toString('base64')}:${encrypted.toString('base64')}`
}

export function decryptSecret(payload: string): string {
  const [ivB64, tagB64, dataB64] = payload.split(':')
  if (!ivB64 || !tagB64 || !dataB64) throw new Error('Invalid encrypted payload')
  const decipher = createDecipheriv(ALGORITHM, getEncryptionKey(), Buffer.from(ivB64, 'base64'))
  decipher.setAuthTag(Buffer.from(tagB64, 'base64'))
  const decrypted = Buffer.concat([decipher.update(Buffer.from(dataB64, 'base64')), decipher.final()])
  return decrypted.toString('utf8')
}

export function maskApiKey(key: string): string {
  if (key.length <= 8) return '••••••••'
  return `${key.slice(0, 4)}••••••••${key.slice(-4)}`
}

